--
-- Table structure for table `prompt_technique`
--

DROP TABLE IF EXISTS `prompt_technique`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `prompt_technique` (
  `technique_id` int NOT NULL AUTO_INCREMENT,
  `technique_name` varchar(50) NOT NULL COMMENT 'Technique name e.g. zero-shot, few-shot, chain-of-thought, structured-output',
  `system_prompt_file` varchar(500) NOT NULL COMMENT 'Relative path to system prompt file e.g. prompts/zero_shot_system.txt',
  `user_prompt_file` varchar(500) NOT NULL COMMENT 'Relative path to user prompt template file e.g. prompts/zero_shot_user.txt',
  `prompt_version` varchar(10) NOT NULL COMMENT 'Version of the prompt files e.g. 1.0',
  `description` text COMMENT 'Brief description of the technique and its characteristics',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT 'Record creation timestamp',
  PRIMARY KEY (`technique_id`)
) ENGINE=InnoDB AUTO_INCREMENT=5 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='Reference table for the four prompt engineering techniques';
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `prompt_technique`
--

LOCK TABLES `prompt_technique` WRITE;
/*!40000 ALTER TABLE `prompt_technique` DISABLE KEYS */;
INSERT INTO `prompt_technique` VALUES (1,'zero-shot','prompts/zero_shot_system.txt','prompts/zero_shot_user.txt','1.0','Zero-shot prompting provides the model with task instructions and output format requirements only, without any examples. The model relies entirely on its pretrained knowledge to extract nutritional information from EN-MS code-switched cooking transcripts.','2026-06-22 07:50:22'),(2,'few-shot','prompts/few_shot_system.txt','prompts/few_shot_user.txt','1.0','Few-shot prompting supplies the model with a small number of annotated input-output examples before the target transcript. This guides the model toward the expected JSON output structure and handling of informal Malay culinary expressions.','2026-06-22 07:50:22'),(3,'chain-of-thought','prompts/chain_of_thought_system.txt','prompts/chain_of_thought_user.txt','1.0','Chain-of-thought prompting instructs the model to reason step-by-step before producing the final JSON output. This encourages explicit intermediate reasoning over ingredient identification, quantity interpretation, and language tagging in code-switched text.','2026-06-22 07:50:22'),(4,'structured-output','prompts/structured_output_system.txt','prompts/structured_output_user.txt','1.0','Structured-output prompting enforces a strict JSON schema in the prompt instructions, constraining the model response to a predefined format. This reduces hallucination risk and improves consistency of the extracted nutritional fields across all five LLMs.','2026-06-22 07:50:22');
/*!40000 ALTER TABLE `prompt_technique` ENABLE KEYS */;
UNLOCK TABLES;

