  `video_duration_sec` int DEFAULT NULL COMMENT 'Duration of the video in seconds',
  `language_tag` varchar(20) DEFAULT 'code-switched' COMMENT 'Language of the reel: EN, MY, or code-switched',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT 'Record creation timestamp',
  PRIMARY KEY (`reel_id`),
  KEY `fk_reel_influencer` (`influencer_id`),
